mapper.select:
select a.activity_id as activityId, a.creator_user_id as creatorUserId, a.title as title, a.activity_type as activityType, a.location as location, a.start_time as startTime, a.end_time as endTime, a.pet_size_limit as petSizeLimit, a.max_participants as maxParticipants, a.current_participants as currentParticipants, a.status as status, a.review_status as reviewStatus, a.review_by as reviewBy, a.review_time as reviewTime, a.review_note as reviewNote, a.description as description, a.create_time as createTime, u.nick_name as creatorName from biz_community_activity a left join sys_user u on u.user_id = a.creator_user_id
and a.creator_user_id = #{creatorUserId} and a.review_status = #{reviewStatus}
order by a.create_time desc

select count(1)
from biz_activity_signup
where activity_id = #{activityId}
  and user_id = #{userId}
  and pet_id = #{petId}
  and status = '0'
